"""
Parameterized generator for GH896_gpytorch_1299.

Source PR:    https://github.com/cornellius-gp/gpytorch/pull/1299
Source Issue: https://github.com/cornellius-gp/gpytorch/issues/1298

Seed varies: renames 'accommodate' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH896_gpytorch_1299'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH896_gpytorch_1299'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accommodate', 'accommodate' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH896_gpytorch_1299',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'cornellius-gp/gpytorch',
                "pr_number": 1299,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/cornellius-gp/gpytorch/pull/1299",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'gpytorch/lazy/added_diag_lazy_tensor.py': '#!/usr/bin/env python3\n\nimport warnings\nfrom typing import Optional, Tuple\n\nimport torch\nfrom torch import Tensor\n\nfrom .. import settings\nfrom ..utils import broadcasting, pivoted_cholesky\nfrom ..utils.memoize import cached\nfrom ..utils.warnings import NumericalWarning\nfrom .diag_lazy_tensor import ConstantDiagLazyTensor, DiagLazyTensor\nfrom .lazy_tensor import LazyTensor\nfrom .psd_sum_lazy_tensor import PsdSumLazyTensor\nfrom .root_lazy_tensor import RootLazyTensor\nfrom .sum_lazy_tensor import SumLazyTensor\n\n\nclass AddedDiagLazyTensor(SumLazyTensor):\n    """\n    A SumLazyTensor, but of only two lazy tensors, the second of which must be\n    a DiagLazyTensor.\n    """\n\n    def __init__(self, *lazy_tensors, preconditioner_override=None):\n        lazy_tensors = list(lazy_tensors)\n        super(AddedDiagLazyTensor, self).__init__(*lazy_tensors, preconditioner_override=preconditioner_override)\n        if len(lazy_tensors) > 2:\n            raise RuntimeError("An AddedDiagLazyTensor can only have two components")\n\n        broadcasting._mul_broadcast_shape(lazy_tensors[0].shape, lazy_tensors[1].shape)\n\n        if isinstance(lazy_tensors[0], DiagLazyTensor) and isinstance(lazy_tensors[1], DiagLazyTensor):\n            raise RuntimeError("Trying to lazily add two DiagLazyTensors. Create a single DiagLazyTensor instead.")\n        elif isinstance(lazy_tensors[0], DiagLazyTensor):\n            self._diag_tensor = lazy_tensors[0]\n            self._lazy_tensor = lazy_tensors[1]\n        elif isinstance(lazy_tensors[1], DiagLazyTensor):\n            self._diag_tensor = lazy_tensors[1]\n            self._lazy_tensor = lazy_tensors[0]\n        else:\n            raise RuntimeError("One of the LazyTensors input to AddedDiagLazyTensor must be a DiagLazyTensor!")\n\n        self.preconditioner_override = preconditioner_override\n\n        # Placeholders\n        self._constant_diag = None\n        self._noise = None\n        self._piv_chol_self = None  # <- Doesn\'t need to be an attribute, but used for testing purposes\n        self._precond_lt = None\n        self._precond_logdet_cache = None\n        self._q_cache = None\n        self._r_cache = None\n\n    def _matmul(self, rhs):\n        return torch.addcmul(self._lazy_tensor._matmul(rhs), self._diag_tensor._diag.unsqueeze(-1), rhs)\n\n    def add_diag(self, added_diag):\n        return AddedDiagLazyTensor(self._lazy_tensor, self._diag_tensor.add_diag(added_diag))\n\n    def __add__(self, other):\n        from .diag_lazy_tensor import DiagLazyTensor\n\n        if isinstance(other, DiagLazyTensor):\n            return AddedDiagLazyTensor(self._lazy_tensor, self._diag_tensor + other)\n        else:\n            return AddedDiagLazyTensor(self._lazy_tensor + other, self._diag_tensor)\n\n    def _preconditioner(self):\n        if self.preconditioner_override is not None:\n            return self.preconditioner_override(self)\n\n        if settings.max_preconditioner_size.value() == 0 or self.size(-1) < settings.min_preconditioning_size.value():\n            return None, None, None\n\n        if self._q_cache is None:\n            max_iter = settings.max_preconditioner_size.value()\n            self._piv_chol_self = pivoted_cholesky.pivoted_cholesky(self._lazy_tensor, max_iter)\n            if torch.any(torch.isnan(self._piv_chol_self)).item():\n                warnings.warn(\n                    "NaNs encountered in preconditioner computation. Attempting to continue without preconditioning.",\n                    NumericalWarning,\n                )\n                return None, None, None\n            self._init_cache()\n\n        # NOTE: We cannot memoize this precondition closure as it causes a memory leak\n        def precondition_closure(tensor):\n            qqt = self._q_cache.matmul(self._q_cache.transpose(-2, -1).matmul(tensor))\n            if self._constant_diag:\n                return (1 / self._noise) * (tensor - qqt)\n            return (tensor / self._noise) - qqt\n\n        return (precondition_closure, self._precond_lt, self._precond_logdet_cache)\n\n    def _init_cache(self):\n        *batch_shape, n, k = self._piv_chol_self.shape\n        self._noise = self._diag_tensor.diag().unsqueeze(-1)\n\n        # the check for constant diag needs to be done carefully for batches.\n        noise_first_element = self._noise[..., :1, :]\n        self._constant_diag = torch.equal(self._noise, noise_first_element * torch.ones_like(self._noise))\n        eye = torch.eye(k, dtype=self._piv_chol_self.dtype, device=self._piv_chol_self.device)\n\n        if self._constant_diag:\n            self._init_cache_for_constant_diag(eye, batch_shape, n, k)\n        else:\n            self._init_cache_for_non_constant_diag(eye, batch_shape, n)\n\n        self._precond_lt = PsdSumLazyTensor(RootLazyTensor(self._piv_chol_self), self._diag_tensor)\n\n    def _init_cache_for_constant_diag(self, eye, batch_shape, n, k):\n        # We can factor out the noise for for both QR and solves.\n        self._noise = self._noise.narrow(-2, 0, 1)\n        self._q_cache, self._r_cache = torch.qr(torch.cat((self._piv_chol_self, self._noise.sqrt() * eye), dim=-2))\n        self._q_cache = self._q_cache[..., :n, :]\n\n        # Use the matrix determinant lemma for the logdet, using the fact that R\'R = L_k\'L_k + s*I\n        logdet = self._r_cache.diagonal(dim1=-1, dim2=-2).abs().log().sum(-1).mul(2)\n        logdet = logdet + (n - k) * self._noise.squeeze(-2).squeeze(-1).log()\n        self._precond_logdet_cache = logdet.view(*batch_shape) if len(batch_shape) else logdet.squeeze()\n\n    def _init_cache_for_non_constant_diag(self, eye, batch_shape, n):\n        # With non-constant diagonals, we cant factor out the noise as easily\n        self._q_cache, self._r_cache = torch.qr(torch.cat((self._piv_chol_self / self._noise.sqrt(), eye)))\n        self._q_cache = self._q_cache[..., :n, :] / self._noise.sqrt()\n\n        logdet = self._r_cache.diagonal(dim1=-1, dim2=-2).abs().log().sum(-1).mul(2)\n        logdet -= (1.0 / self._noise).log().sum([-1, -2])\n        self._precond_logdet_cache = logdet.view(*batch_shape) if len(batch_shape) else logdet.squeeze()\n\n    @cached(name="svd")\n    def _svd(self) -> Tuple["LazyTensor", Tensor, "LazyTensor"]:\n        if isinstance(self._diag_tensor, ConstantDiagLazyTensor):\n            U, S_, V = self._lazy_tensor.svd()\n            S = S_ + self._diag_tensor.diag()\n            return U, S, V\n        return super()._svd()\n\n    def _symeig(self, eigenvectors: bool = False) -> Tuple[Tensor, Optional[LazyTensor]]:\n        if isinstance(self._diag_tensor, ConstantDiagLazyTensor):\n            evals_, evecs = self._lazy_tensor.symeig(eigenvectors=eigenvectors)\n            evals = evals_ + self._diag_tensor.diag()\n            return evals, evecs\n        return super()._symeig(eigenvectors=eigenvectors)\n',
            'test/examples/test_white_noise_regression.py': '#!/usr/bin/env python3\n\nimport os\nimport random\nimport unittest\nimport warnings\nfrom math import exp, pi\n\nimport gpytorch\nimport torch\nfrom gpytorch.distributions import MultivariateNormal\nfrom gpytorch.kernels import RBFKernel, ScaleKernel\nfrom gpytorch.likelihoods import GaussianLikelihood, FixedNoiseGaussianLikelihood\nfrom gpytorch.means import ConstantMean\nfrom gpytorch.priors import SmoothedBoxPrior\nfrom gpytorch.test.utils import least_used_cuda_device\nfrom gpytorch.utils.warnings import GPInputWarning\nfrom torch import optim\n\n\nclass ExactGPModel(gpytorch.models.ExactGP):\n    def __init__(self, train_inputs, train_targets, likelihood):\n        super(ExactGPModel, self).__init__(train_inputs, train_targets, likelihood)\n        self.mean_module = ConstantMean(prior=SmoothedBoxPrior(-1, 1))\n        self.rbf_covar_module = RBFKernel(lengthscale_prior=SmoothedBoxPrior(exp(-3), exp(3), sigma=0.1))\n        self.covar_module = ScaleKernel(self.rbf_covar_module)\n\n    def forward(self, x):\n        mean_x = self.mean_module(x)\n        covar_x = self.covar_module(x)\n        return MultivariateNormal(mean_x, covar_x)\n\n\nclass TestWhiteNoiseGPRegression(unittest.TestCase):\n    def setUp(self):\n        if os.getenv("UNLOCK_SEED") is None or os.getenv("UNLOCK_SEED").lower() == "false":\n            self.rng_state = torch.get_rng_state()\n            torch.manual_seed(1)\n            if torch.cuda.is_available():\n                torch.cuda.manual_seed_all(1)\n            random.seed(1)\n\n    def tearDown(self):\n        if hasattr(self, "rng_state"):\n            torch.set_rng_state(self.rng_state)\n\n    def _get_data(self, cuda=False):\n        device = torch.device("cuda") if cuda else torch.device("cpu")\n        # Simple training data: let\'s try to learn a sine function\n        train_x = torch.linspace(0, 1, 11, device=device)\n        train_y = torch.sin(train_x * (2 * pi))\n        test_x = torch.linspace(0, 1, 51, device=device)\n        test_y = torch.sin(test_x * (2 * pi))\n        return train_x, test_x, train_y, test_y\n\n    def test_posterior_latent_gp_and_likelihood_without_optimization(self, cuda=False):\n        train_x, test_x, train_y, test_y = self._get_data(cuda=cuda)\n        with gpytorch.settings.debug(False):\n            # We\'re manually going to set the hyperparameters to be ridiculous\n            likelihood = FixedNoiseGaussianLikelihood(torch.ones(11) * 1e-8)\n            gp_model = ExactGPModel(train_x, train_y, likelihood)\n            # Update lengthscale prior to accommodate extreme parameters\n            gp_model.rbf_covar_module.initialize(lengthscale=exp(-6))\n            gp_model.mean_module.initialize(constant=0)\n\n            if cuda:\n                gp_model.cuda()\n                likelihood.cuda()\n\n            # Compute posterior distribution\n            gp_model.eval()\n            likelihood.eval()\n\n            # Let\'s see how our model does, conditioned with weird hyperparams\n            # The posterior should fit all the data\n            function_predictions = likelihood(gp_model(train_x))\n\n            self.assertLess(torch.norm(function_predictions.mean - train_y), 1e-3)\n            self.assertLess(torch.norm(function_predictions.variance), 5e-3)\n\n            # It shouldn\'t fit much else though\n            test_function_predictions = gp_model(torch.tensor([1.1]).type_as(test_x))\n\n            self.assertLess(torch.norm(test_function_predictions.mean - 0), 1e-4)\n            self.assertLess(torch.norm(test_function_predictions.variance - gp_model.covar_module.outputscale), 1e-4)\n\n    def test_posterior_latent_gp_and_likelihood_without_optimization_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_posterior_latent_gp_and_likelihood_without_optimization(cuda=True)\n\n    def test_posterior_latent_gp_and_likelihood_with_optimization(self, cuda=False):\n        # This test throws a warning because the fixed noise likelihood gets the wrong input\n        warnings.simplefilter("ignore", GPInputWarning)\n\n        train_x, test_x, train_y, test_y = self._get_data(cuda=cuda)\n        # We\'re manually going to set the hyperparameters to something they shouldn\'t be\n        likelihood = FixedNoiseGaussianLikelihood(torch.ones(11) * 0.001)\n        gp_model = ExactGPModel(train_x, train_y, likelihood)\n        mll = gpytorch.ExactMarginalLogLikelihood(likelihood, gp_model)\n        gp_model.rbf_covar_module.initialize(lengthscale=exp(1))\n        gp_model.mean_module.initialize(constant=0)\n\n        if cuda:\n            gp_model.cuda()\n            likelihood.cuda()\n\n        # Find optimal model hyperparameters\n        gp_model.train()\n        likelihood.train()\n\n        optimizer = optim.Adam(gp_model.parameters(), lr=0.1)\n        optimizer.n_iter = 0\n        with gpytorch.settings.debug(False):\n            for _ in range(75):\n                optimizer.zero_grad()\n                output = gp_model(train_x)\n                loss = -mll(output, train_y)\n                loss.backward()\n                optimizer.n_iter += 1\n                optimizer.step()\n\n            for param in gp_model.parameters():\n                self.assertTrue(param.grad is not None)\n                self.assertGreater(param.grad.norm().item(), 0)\n            optimizer.step()\n\n            # Test the model\n            gp_model.eval()\n            likelihood.eval()\n            test_function_predictions = likelihood(gp_model(test_x))\n            mean_abs_error = torch.mean(torch.abs(test_y - test_function_predictions.mean))\n\n        self.assertLess(mean_abs_error.squeeze().item(), 0.05)\n\n    def test_posterior_latent_gp_and_likelihood_with_optimization_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_posterior_latent_gp_and_likelihood_with_optimization(cuda=True)\n\n    def test_posterior_latent_gp_and_likelihood_fast_pred_var(self, cuda=False):\n        train_x, test_x, train_y, test_y = self._get_data(cuda=cuda)\n        with gpytorch.settings.fast_pred_var(), gpytorch.settings.debug(False):\n            # We\'re manually going to set the hyperparameters to something they shouldn\'t be\n            likelihood = GaussianLikelihood(noise_prior=SmoothedBoxPrior(exp(-3), exp(3), sigma=0.1))\n            gp_model = ExactGPModel(train_x, train_y, likelihood)\n            mll = gpytorch.mlls.ExactMarginalLogLikelihood(likelihood, gp_model)\n            gp_model.rbf_covar_module.initialize(lengthscale=exp(1))\n            gp_model.mean_module.initialize(constant=0)\n            likelihood.initialize(noise=exp(1))\n\n            if cuda:\n                gp_model.cuda()\n                likelihood.cuda()\n\n            # Find optimal model hyperparameters\n            gp_model.train()\n            likelihood.train()\n            optimizer = optim.Adam(gp_model.parameters(), lr=0.1)\n            optimizer.n_iter = 0\n            for _ in range(50):\n                optimizer.zero_grad()\n                output = gp_model(train_x)\n                loss = -mll(output, train_y)\n                loss.backward()\n                optimizer.n_iter += 1\n                optimizer.step()\n\n            for param in gp_model.parameters():\n                self.assertTrue(param.grad is not None)\n                self.assertGreater(param.grad.norm().item(), 0)\n            optimizer.step()\n\n            # Test the model\n            gp_model.eval()\n            likelihood.eval()\n            # Set the cache\n            test_function_predictions = likelihood(gp_model(train_x))\n\n            # Now bump up the likelihood to something huge\n            # This will make it easy to calculate the variance\n            likelihood.raw_noise.data.fill_(3)\n            test_function_predictions = likelihood(gp_model(train_x))\n\n            noise = likelihood.noise\n            var_diff = (test_function_predictions.variance - noise).abs()\n\n            self.assertLess(torch.max(var_diff / noise), 0.05)\n\n    def test_posterior_latent_gp_and_likelihood_fast_pred_var_cuda(self):\n        if torch.cuda.is_available():\n            with least_used_cuda_device():\n                self.test_posterior_latent_gp_and_likelihood_fast_pred_var(cuda=True)\n\n\nif __name__ == "__main__":\n    unittest.main()\n',
        }
